import org.wordpress.android.R
import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagList
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.ui.compose.components.menu.dropdown.MenuElementData
import org.wordpress.android.ui.utils.UiString.UiStringRes
import org.wordpress.android.ui.utils.UiString.UiStringText
import org.wordpress.android.util.config.ReaderTagsFeedFeatureConfig

class ReaderTopBarMenuHelperReproductionTest {
    private val readerTagsFeedFeatureConfig: ReaderTagsFeedFeatureConfig = mock()
    val helper = ReaderTopBarMenuHelper(
        readerTagsFeedFeatureConfig = readerTagsFeedFeatureConfig
    )

    @Test
    fun `GIVEN 2 custom lists WHEN createMenu THEN lists displayed directly in root`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(createCustomListTag("custom-list-1")) // item 0
            add(createCustomListTag("custom-list-2")) // item 1
        }

        val menu = helper.createMenu(tags)

        // Verify Divider is added
        assertThat(menu).contains(MenuElementData.Divider)

        // Verify items are directly in the menu, NOT in a submenu
        val customList1Item = menu.findSingleItem { it.text == UiStringText("custom-list-1") }
        assertThat(customList1Item).isNotNull()
        assertThat(customList1Item?.id).isEqualTo("0")

        val customList2Item = menu.findSingleItem { it.text == UiStringText("custom-list-2") }
        assertThat(customList2Item).isNotNull()
        assertThat(customList2Item?.id).isEqualTo("1")

        // Verify SubMenu does not exist
        val subMenu = menu.findSubMenu()
        assertThat(subMenu).isNull()
    }

    @Test
    fun `GIVEN 3 custom lists WHEN createMenu THEN lists displayed in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(createCustomListTag("custom-list-1")) // item 0
            add(createCustomListTag("custom-list-2")) // item 1
            add(createCustomListTag("custom-list-3")) // item 2
        }

        val menu = helper.createMenu(tags)

        // Verify Divider is added
        assertThat(menu).contains(MenuElementData.Divider)

        // Verify items are NOT directly in the menu
        val customList1Item = menu.findSingleItem { it.text == UiStringText("custom-list-1") }
        assertThat(customList1Item).isNull()

        // Verify SubMenu exists
        val subMenu = menu.findSubMenu()
        assertThat(subMenu).isNotNull()
        assertThat(subMenu?.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_lists))
        assertThat(subMenu?.children).hasSize(3)
    }

    @Test
    fun `GIVEN 1 custom list WHEN createMenu THEN list displayed directly in root`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(createCustomListTag("custom-list-1")) // item 0
        }

        val menu = helper.createMenu(tags)

        // Verify Divider is added
        assertThat(menu).contains(MenuElementData.Divider)

        // Verify item is directly in the menu, NOT in a submenu
        val customList1Item = menu.findSingleItem { it.text == UiStringText("custom-list-1") }
        assertThat(customList1Item).isNotNull()
        assertThat(customList1Item?.id).isEqualTo("0")

        // Verify SubMenu does not exist
        val subMenu = menu.findSubMenu()
        assertThat(subMenu).isNull()
    }


    private fun List<MenuElementData>.findSingleItem(
        predicate: (MenuElementData.Item.Single) -> Boolean
    ): MenuElementData.Item.Single? {
        return find { it is MenuElementData.Item.Single && predicate(it) } as? MenuElementData.Item.Single
    }

    private fun List<MenuElementData>.findSubMenu(): MenuElementData.Item.SubMenu? {
        return find { it is MenuElementData.Item.SubMenu } as? MenuElementData.Item.SubMenu
    }

    private fun createCustomListTag(title: String): ReaderTag {
        return ReaderTag(
            title,
            title,
            title,
            "http://endpoint.com",
            ReaderTagType.CUSTOM_LIST
        )
    }
}
